// MenuCreateRequest - 创建菜单
type MenuCreateRequest struct {
	Click string `json:"click"` // 成员点击click类型按钮后,企业微信服务器会通过消息接口推送消息类型为event 的结构给开发者(参考消息接口指南),并且带上按钮中开发者填写的key值,开发者可以通过自定义的key值与成员进行交互;
	View string `json:"view"` // 成员点击view类型按钮后,企业微信客户端将会打开开发者在按钮中填写的网页URL,可与网页授权获取成员基本信息接口结合,获得成员基本信息.
	AccessToken string `json:"access_token"` // 调用接口凭证
	Agentid string `json:"agentid"` // 企业应用的id,整型.可在应用的设置页面查看
	Button string `json:"button"` // 一级菜单数组,个数应为1~3个
	SubButton string `json:"sub_button"` // 二级菜单数组,个数应为1~5个
	Type string `json:"type"` // 菜单的响应动作类型
	Name string `json:"name"` // 菜单的名字.不能为空,主菜单不能超过16字节,子菜单不能超过40字节.
	Key string `json:"key"` // 菜单KEY值,用于消息接口推送,不超过128字节
	URL string `json:"url"` // 网页链接,成员点击菜单可打开链接,不超过1024字节.为了提高安全性,建议使用https的url
	Pagepath string `json:"pagepath"` // 小程序的页面路径
	Appid string `json:"appid"` // 小程序的appid(仅与企业绑定的小程序可配置)
}


// MenuCreateResponse - 创建菜单
type MenuCreateResponse struct {
	CommonResponse
	ScancodePush string `json:"scancode_push"` // 成员点击按钮后,企业微信客户端将调起扫一扫工具,完成扫码操作后显示扫描结果(如果是URL,将进入URL),且会将扫码的结果传给开发者,开发者可用于下发消息.
	ScancodeWaitmsg string `json:"scancode_waitmsg"` // 成员点击按钮后,企业微信客户端将调起扫一扫工具,完成扫码操作后,将扫码的结果传给开发者,同时收起扫一扫工具,然后弹出“消息接收中”提示框,随后可能会收到开发者下发的消息.
	PicSysphoto string `json:"pic_sysphoto"` // 弹出系统拍照发图 成员点击按钮后,企业微信客户端将调起系统相机,完成拍照操作后,会将拍摄的相片发送给开发者,并推送事件给开发者,同时收起系统相机,随后可能会收到开发者下发的消息.
	PicPhotoOrAlbum string `json:"pic_photo_or_album"` // 成员点击按钮后,企业微信客户端将弹出选择器供成员选择“拍照”或者“从手机相册选择”.成员选择后即走其他两种流程.
	PicWeixin string `json:"pic_weixin"` // 成员点击按钮后,企业微信客户端将调起企业微信相册,完成选择操作后,将选择的相片发送给开发者的服务器,并推送事件给开发者,同时收起相册,随后可能会收到开发者下发的消息.
	LocationSelect string `json:"location_select"` // 成员点击按钮后,企业微信客户端将调起地理位置选择工具,完成选择操作后,将选择的地理位置发送给开发者的服务器,同时收起位置选择工具,随后可能会收到开发者下发的消息.
	ViewMiniprogram string `json:"view_miniprogram"` // 成员点击按钮后,企业微信客户端将会打开开发者在按钮中配置的小程序
}


