// CheckinGetcheckindataRequest - 获取打卡记录数据
type CheckinGetcheckindataRequest struct {
	AccessToken string `json:"access_token"` // 调用接口凭证,获取方式参考:文档-获取access_token
	Opencheckindatatype string `json:"opencheckindatatype"` // 打卡类型.1:上下班打卡;2:外出打卡;3:全部打卡
	Starttime int64 `json:"starttime"` // 获取打卡记录的开始时间.Unix时间戳
	Endtime int64 `json:"endtime"` // 获取打卡记录的结束时间.Unix时间戳
	Useridlist []string `json:"useridlist"` // 需要获取打卡记录的用户列表
	Userid string `json:"userid"` // 用户id
	Groupname string `json:"groupname"` // 打卡规则名称
	CheckinType string `json:"checkin_type"` // 打卡类型.字符串,目前有:上班打卡,下班打卡,外出打卡,仅记录打卡时间和位置
	ExceptionType string `json:"exception_type"` // 异常类型,字符串,包括:时间异常,地点异常,未打卡,wifi异常,非常用设备.如果有多个异常,以分号间隔
	CheckinTime int64 `json:"checkin_time"` // 打卡时间.Unix时间戳
	LocationTitle string `json:"location_title"` // 打卡地点title
	LocationDetail string `json:"location_detail"` // 打卡地点详情
	Wifiname string `json:"wifiname"` // 打卡wifi名称
	Notes string `json:"notes"` // 打卡备注
	Wifimac string `json:"wifimac"` // 打卡的MAC地址/bssid
	Mediaids []string `json:"mediaids"` // 打卡的附件media_id,可使用media/get获取附件
	Lat string `json:"lat"` // 位置打卡地点纬度,是实际纬度的1000000倍,与腾讯地图一致采用GCJ-02坐标系统标准
	Lng string `json:"lng"` // 位置打卡地点经度,是实际经度的1000000倍,与腾讯地图一致采用GCJ-02坐标系统标准
	Deviceid string `json:"deviceid"` // 打卡设备id
	SchCheckinTime int64 `json:"sch_checkin_time"` // 标准打卡时间,指此次打卡时间对应的标准上班时间或标准下班时间
	Groupid string `json:"groupid"` // 规则id,表示打卡记录所属规则的id
	ScheduleID string `json:"schedule_id"` // 班次id,表示打卡记录所属规则中,所属班次的id
	TimelineID string `json:"timeline_id"` // 时段id,表示打卡记录所属规则中,某一班次中的某一时段的id,如上下班时间为9:00-12:00,13:00-18:00的班次中,9:00-12:00为其中一组时段
}


// CheckinGetcheckinoptionRequest - 获取员工打卡规则
