// AgentGetWorkbenchDataRequest - 设置工作台自定义展示
type AgentGetWorkbenchDataRequest struct {
	Items string `json:"items"` // 关键数据型数组,不超过4个
	URL string `json:"url"` // 图片url.图片的最佳比例为3.35:1
	JumpURL string `json:"jump_url"` // 点击跳转url.若不填且应用设置了主页url,则跳转到主页url,否则跳到应用会话窗口.仅当应用主页为网页时配置生效,若应用主页为小程序,填写该字段不同的客户端平台或者版本表现可能不一致
	Pagepath string `json:"pagepath"` // 若应用为小程序类型,该字段填小程序pagepath,若未设置,跳到小程序主页.仅当应用主页为小程序时配置生效,若应用主页为网页,填写该字段不同的客户端平台或者版本表现可能不一致
	Height string `json:"height"` // 高度.可以有两种选择:single_row与double_row.当为single_row时,高度为106px(如果隐藏标题则为147px).当为double_row时,高度固定为171px(如果隐藏标题则为212px).默认值为double_row
	HideTitle string `json:"hide_title"` // 是否要隐藏展示了应用名称的标题部分,默认值为false
	EnableWebviewClick string `json:"enable_webview_click"` // 是否开启webview内的链接跳转能力,默认值为false.注意:开启之后,会使jump_url失效.链接跳转仅支持以下schema方式:wxwork://openurl?url=xxxx,注意url需要进行编码.参考示例:<a href="wxwork://openurl?url=https%3A%2F%2Fwork.weixin.qq.com%2F">今日要闻</a>
	AccessToken string `json:"access_token"` // 调用接口凭证
	Type string `json:"type"` // 模版类型,目前支持的自定义类型包括 "keydata", "image", "list", "webview" .若设置的type为 "normal",则相当于从自定义模式切换为普通宫格或者列表展示模式
	Agentid string `json:"agentid"` // 应用id
	Keydata string `json:"keydata"` // 若type指定为 "keydata",且需要设置企业级别默认数据,则需要设置关键数据型模版数据,数据结构参考“关键数据型”
	Image string `json:"image"` // 若type指定为 "image",且需要设置企业级别默认数据,则需要设置图片型模版数据,数据结构参考“图片型”
	List []string `json:"list"` // 若type指定为 "list",且需要设置企业级别默认数据,则需要设置列表型模版数据,数据结构参考“列表型”
	Webview string `json:"webview"` // 若type指定为 "webview",且需要设置企业级别默认数据,则需要设置webview型模版数据,数据结构参考“webview型”
	ReplaceUserData string `json:"replace_user_data"` // 是否覆盖用户工作台的数据.设置为true的时候,会覆盖企业所有用户当前设置的数据.若设置为false,则不会覆盖用户当前设置的所有数据.默认为false
	Userid string `json:"userid"` // 需要设置的用户的userid
	UseridList []string `json:"userid_list"` // 需要设置的用户userid列表,最多1000个
	Useridt string `json:"useridt"` // 用户userid
	Tousername string `json:"tousername"` // 企业微信CorpID
	Fromusername string `json:"fromusername"` // 此处固定为sys
	Createtime int64 `json:"createtime"` // 消息创建时间(整型)
	Msgtype string `json:"msgtype"` // 消息类型,此时固定为:event
	Event string `json:"event"` // 事件类型:switch_workbench_mode,切换工作台自定义模式
	Mode string `json:"mode"` // 1表示开启工作台自定义模式,0表示关闭工作台自定义模式
}


