// CheckinSetcheckinschedulistRequest - 为打卡人员排班
type CheckinSetcheckinschedulistRequest struct {
	AccessToken string `json:"access_token"` // 调用接口凭证.获取方式参考:文档-获取access_token
	Items string `json:"items"` // 排班表信息
	Groupid string `json:"groupid"` // 打卡规则的规则id,可通过“获取打卡规则”,“获取打卡数据”,“获取打卡人员排班信息”等相关接口获取
	Userid string `json:"userid"` // 打卡人员userid
	Day string `json:"day"` // 要设置的天日期,取值在1-31之间.联合yearmonth组成唯一日期 比如20201205
	ScheduleID string `json:"schedule_id"` // 对应groupid规则下的班次id,通过预先拉取规则信息获取,0代表休息
	Yearmonth string `json:"yearmonth"` // 排班表月份,格式为年月,如202011
}


// CheckinSetcheckinschedulistResponse - 为打卡人员排班
type CheckinSetcheckinschedulistResponse struct {
	CommonResponse
}


