type OaScheduleAddResponse struct {
	CommonResponse
	ScheduleAdmins string `json:"schedule.admins"` // 日程的管理员userid列表,管理员必须在共享成员的列表中.最多指定3人
	ScheduleAttendees []interface{} `json:"schedule.attendees"` // 日程参与者列表.最多支持1000人
	ScheduleAttendeesUserid string `json:"schedule.attendees.userid"` // 日程参与者ID不多于64字节
	ScheduleSummary string `json:"schedule.summary"` // 日程标题.0 ~ 128 字符.不填会默认显示为“新建事件”
	ScheduleDescription string `json:"schedule.description"` // 日程描述不多于1000个字符
	ScheduleReminders string `json:"schedule.reminders"` // 提醒相关信息
	ScheduleRemindersIsRemind int `json:"schedule.reminders.is_remind"` // 是否需要提醒.0-否;1-是
	ScheduleRemindersIsRepeat int `json:"schedule.reminders.is_repeat"` // 是否重复日程.0-否;1-是
	ScheduleRemindersRemindBeforeEventSecs int `json:"schedule.reminders.remind_before_event_secs"` // 日程开始(start_time)前多少秒提醒,当is_remind为1时有效.例如: 300表示日程开始前5分钟提醒.目前仅支持以下数值:0 - 事件开始时300 - 事件开始前5分钟900 - 事件开始前15分钟3600 - 事件开始前1小时86400 - 事件开始前1天
	ScheduleRemindersRemindTimeDiffs int64 `json:"schedule.reminders.remind_time_diffs"` // 提醒时间与日程开始时间(start_time)的差值,当is_remind为1时有效,可以指定多个提醒时间,目前仅支持以下数值:0 - 事件开始时-300 - 事件开始前5分钟-900 - 事件开始前15分钟-3600 - 事件开始前1小时-86400 - 事件开始前1天当is_whole_day=1时,还支持:32400 - 事件开始当天(09:00)-172800 - 事件开始前两天-604800 - 事件开始前1周该字段与remind_before_event_secs仅一个字段会生效,当该字段有传值且列表不为空时,优先以该字段为准
	ScheduleRemindersRepeatType int `json:"schedule.reminders.repeat_type"` // 重复类型,当is_repeat为1时有效.目前支持如下类型:0 - 每日1 - 每周2 - 每月5 - 每年7 - 工作日
	ScheduleRemindersRepeatUntil int `json:"schedule.reminders.repeat_until"` // 重复结束时刻,Unix时间戳,当is_repeat为1时有效.不填或填0表示一直重复
	ScheduleRemindersIsCustomRepeat int `json:"schedule.reminders.is_custom_repeat"` // 是否自定义重复.0-否;1-是.当is_repeat为1时有效.
	ScheduleRemindersRepeatInterval int `json:"schedule.reminders.repeat_interval"` // 重复间隔仅当指定为自定义重复时有效该字段随repeat_type不同而含义不同例如:repeat_interval指定为3,repeat_type指定为每周重复,那么每3周重复一次;repeat_interval指定为3,repeat_type指定为每月重复,那么每3个月重复一次
	ScheduleRemindersRepeatDayOfWeek int `json:"schedule.reminders.repeat_day_of_week"` // 每周周几重复仅当指定为自定义重复且重复类型为每周时有效取值范围:1 ~ 7,分别表示周一至周日
	ScheduleRemindersRepeatDayOfMonth int `json:"schedule.reminders.repeat_day_of_month"` // 每月哪几天重复仅当指定为自定义重复且重复类型为每月时有效取值范围:1 ~ 31,分别表示1~31号
	ScheduleRemindersTimezone int64 `json:"schedule.reminders.timezone"` // 时区.UTC偏移量表示(即偏离零时区的小时数),东区为正数,西区为负数.例如:+8 表示北京时间东八区默认为北京时间东八区取值范围:-12 ~ +12
	ScheduleLocation string `json:"schedule.location"` // 日程地址不多于128个字符
	ScheduleStartTime int64 `json:"schedule.start_time"` // 日程开始时间,Unix时间戳
	ScheduleEndTime int64 `json:"schedule.end_time"` // 日程结束时间,Unix时间戳
	ScheduleCalID string `json:"schedule.cal_id"` // 日程所属日历ID.该日历必须是access_token所对应应用所创建的日历.如果不填,那么插入到access_token所对应应用的默认日历上.第三方应用必须指定cal_id不多于64字节
	ScheduleIsWholeDay int `json:"schedule.is_whole_day"` // 是否设置为全天日程.0-否;1-是
	ScheduleID string `json:"schedule_id"` // 日程ID
}


