// MeetingCreateRequest - 创建预约会议
type MeetingCreateRequest struct {
	AccessToken string `json:"access_token"` // 调用接口凭证.获取方法查看“获取access_token”
	AdminUserid string `json:"admin_userid"` // 会议管理员userid
	Title string `json:"title"` // 会议的标题,最多支持40个字节或者20个utf8字符
	MeetingStart string `json:"meeting_start"` // 会议开始时间的unix时间戳.需大于当前时间
	MeetingDuration string `json:"meeting_duration"` // 会议持续时间(单位秒),最小300秒,最大86399秒
	Description string `json:"description"` // 会议的描述,最多支持500个字节或者utf8字符
	Location string `json:"location"` // 会议地点,最多128个字符
	Agentid string `json:"agentid"` // 授权方安装的应用agentid.仅旧的第三方多应用套件需要填此参数
	Invitees string `json:"invitees"` // 邀请参会的成员.任何userid不合法或者不在应用可见范围,直接报错.参会人数上限不超过指定的「管理员」可预约的人数的上限,普通企业参会人员最多为100人;付费企业不超过企业选购的在线会议室容量,但最多为300人,超过300人请调用更新会议受邀成员列表接口.
	CalID string `json:"cal_id"` // 会议所属日历ID.该日历必须是access_token所对应应用所创建的日历.注意,若参与人在日历分享范围内,则插入到该日历(同时会插入会议参与人的默认日历),若不在分享范围内,否则仅插入到参与者默认日历;如果不填,那么插入到参与者的默认日历上.第三方应用必须指定cal_id不多于64字节
	Password string `json:"password"` // 入会密码,仅可输入4-6位纯数字
	EnableWaitingRoom string `json:"enable_waiting_room"` // 是否开启等候室.true:开启等候室;false:不开启等候室;默认不开
	AllowEnterBeforeHost string `json:"allow_enter_before_host"` // 是否允许成员在主持人进会前加入.true:允许;false:不允许.默认允许
	RemindScope string `json:"remind_scope"` // 会议开始时来电提醒方式,1.不提醒 2.仅提醒主持人 3.提醒所有成员入 4.指定部分人响铃.默认仅提醒主持人
	EnableEnterMute string `json:"enable_enter_mute"` // 成员入会时静音;1:开启;0:关闭;2:超过6人后自动开启静音.默认超过6人自动开启静音
	EnableScreenWatermark string `json:"enable_screen_watermark"` // 是否开启屏幕水印,true:开启;false:不开启.默认不开启
	Hosts string `json:"hosts"` // 会议主持人人列表,主持人员最多10个.若包含ceaater_userid,会自动过滤.任何userid不合法,直接报错.仅购买了高级功能的企业可以指定主持人.
	RingUsers string `json:"ring_users"` // 指定响铃的成员列表.如果remind_scope为4,但是ring_users为空,则全部成员均不响铃.
	IsRepeat string `json:"is_repeat"` // 是否是周期性会议,1:周期性会议 0:非周期性会议.默认为0
	RepeatType string `json:"repeat_type"` // 周期性会议重复类型,0.每天;1.每周;2.每月;7.每个工作日.默认为0.周期性会议该字段才生效
	RepeatUntil string `json:"repeat_until"` // 重复结束时刻.周期性会议该字段才生效.若会议结束时间超出最大结束时间或者未设置,则默认设置为最大结束时间.每天\每个工作日\每周 最多重复200次会议;每两周\每月最多重复50次会议
	RepeatInterval string `json:"repeat_interval"` // 重复间隔.目前仅当repeat_type为1时,即周期为周时,支持设置该字段,且值不能大于2.
	RemindBefore string `json:"remind_before"` // 指定会议开始前多久提醒成员,相对于meeting_start前的秒数,默认不提醒.目前仅支持 0:会议开始时提醒;300:5分钟前提醒;900:15分钟前提醒;3600:一小时前提醒;86400一天前提醒.若指定了非支持的值,则表现为会议开始时提醒
}


