// KFServiceStateTransRequest - 分配客服会话
type KFServiceStateTransRequest struct {
	Code0 string `json:"0"` // 新会话接入(客户发消息咨询).可选择:1.直接用API自动回复消息.2.放进待接入池等待接待人员接待.3.指定接待人员(接待人员须处于“正在接待”中,下同)进行接待
	Code1 string `json:"1"` // 可使用API回复消息.可选择转入待接入池或者指定接待人员处理.
	Code2 string `json:"2"` // 在待接入池中排队等待接待人员接入.可选择转为指定人员接待
	Code3 string `json:"3"` // 人工接待中.可选择转接给其他接待人员处理或者结束会话.
	Code4 string `json:"4"` // 会话已经结束或未开始(客户进入会话,还没上行消息).不允许通过API变更会话状态,客户发消息咨询后会话状态变为“未处理”.接待人员通过客户端在已结束会话中成功发送消息后,会话状态变为“由人工接待”,此时会产生会话状态变更回调事件(4-重新接入已结束/已转接会话).
	AccessToken string `json:"access_token"` // 调用接口凭证
	OpenKFid string `json:"open_kfid"` // 客服账号ID
	ExternalUserid string `json:"external_userid"` // 微信客户的external_userid
	ServiceState string `json:"service_state"` // 变更的目标状态,状态定义和所允许的变更可参考概述中的流程图和表格
}


// KFServiceStateTransResponse - 分配客服会话
