// LicenseCreateNewOrderRequest - 下单购买账号
type LicenseCreateNewOrderRequest struct {
	ProviderAccessToken string `json:"provider_access_token"` // 应用服务商的接口调用凭证,获取方法参见服务商的凭证
	Corpid string `json:"corpid"` // 企业id
	BuyerUserid string `json:"buyer_userid"` // 下单人.服务商企业内成员的明文userid.该userid必须登录过企业微信,并且企业微信已绑定微信,且必须为服务商企业内具有“购买接口许可”权限的管理员.最终也支持由其他人支付
	AccountCount int `json:"account_count"` // 账号个数详情,基础账号跟互通账号不能同时为0
	AccountDuration int `json:"account_duration"` // 账号购买时长.总购买时长为(months*31+days)天,最少购买1个月(31天),最多购买60个月(1860天).若企业为服务商测试企业,只支持购买1个月,不支持指定天购买
}


// LicenseCreateNewOrderResponse - 下单购买账号
